import { useState, useEffect, useRef } from "react";

// ── Data ───────────────────────────────────────────────────────────────────
const STATS = [
  { value: "247", label: "Promises Tracked", icon: "📋", suffix: "" },
  { value: "89",  label: "Politicians Monitored", icon: "👤", suffix: "+" },
  { value: "34",  label: "Fulfilment Rate", icon: "✅", suffix: "%" },
  { value: "52",  label: "Active Districts", icon: "🗺️", suffix: "K" },
];

const POLITICIANS = [
  {
    name: "Anura K. Dissanayake",
    role: "President",
    party: "NPP",
    avatar: "AK",
    color: "#ef4444",
    kept: 2, total: 10, trend: "up",
    tags: ["Governance", "Economy"],
  },
  {
    name: "Ranil Wickremesinghe",
    role: "Former President",
    party: "UNP",
    avatar: "RW",
    color: "#f59e0b",
    kept: 6, total: 18, trend: "neutral",
    tags: ["Finance", "Energy"],
  },
  {
    name: "Sajith Premadasa",
    role: "Opposition Leader",
    party: "SJB",
    avatar: "SP",
    color: "#10b981",
    kept: 3, total: 14, trend: "down",
    tags: ["Housing", "Education"],
  },
];

const PROMISES = [
  { politician: "AKD", text: "Abolish executive presidency", status: "Pending", category: "Governance", days: 152 },
  { politician: "AKD", text: "Recover stolen assets within first year", status: "In Progress", category: "Finance", days: 152 },
  { politician: "RW",  text: "Reduce fuel queues within 3 months", status: "Kept", category: "Energy", days: 840 },
  { politician: "SP",  text: "Build 100,000 homes for low-income families", status: "Broken", category: "Housing", days: 1960 },
  { politician: "RW",  text: "IMF restructuring programme implementation", status: "In Progress", category: "Finance", days: 750 },
  { politician: "SP",  text: "Increase teacher salaries by 50%", status: "Pending", category: "Education", days: 1960 },
];

const NEWS = [
  { tag: "Economy", headline: "President AKD meets IMF delegation over debt restructuring", time: "2h ago" },
  { tag: "Governance", headline: "Parliament debates constitutional reform bill for third week", time: "5h ago" },
  { tag: "Housing", headline: "SJB's housing promise deadline passes with zero units built", time: "1d ago" },
  { tag: "Energy", headline: "Fuel stabilisation milestone cited as UNP legacy win", time: "2d ago" },
];

const STATUS_CFG = {
  "Kept":        { bg: "bg-emerald-500/15", text: "text-emerald-400", border: "border-emerald-500/25", dot: "bg-emerald-400" },
  "Broken":      { bg: "bg-rose-500/15",    text: "text-rose-400",    border: "border-rose-500/25",    dot: "bg-rose-400" },
  "In Progress": { bg: "bg-amber-500/15",   text: "text-amber-400",   border: "border-amber-500/25",   dot: "bg-amber-400" },
  "Pending":     { bg: "bg-slate-600/20",   text: "text-slate-400",   border: "border-slate-600/30",   dot: "bg-slate-500" },
};

const CAT_ICONS = { Governance:"🏛️", Economy:"📊", Finance:"💰", Energy:"⚡", Housing:"🏠", Education:"📚" };

// ── Animated Counter ───────────────────────────────────────────────────────
function Counter({ target, duration = 1800 }) {
  const [val, setVal] = useState(0);
  const ref = useRef(null);
  useEffect(() => {
    const observer = new IntersectionObserver(([e]) => {
      if (!e.isIntersecting) return;
      observer.disconnect();
      const start = performance.now();
      const num = parseInt(target, 10);
      const tick = (now) => {
        const pct = Math.min((now - start) / duration, 1);
        setVal(Math.floor(pct * pct * num));
        if (pct < 1) requestAnimationFrame(tick);
        else setVal(num);
      };
      requestAnimationFrame(tick);
    });
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, [target, duration]);
  return <span ref={ref}>{val}</span>;
}

// ── Donut ──────────────────────────────────────────────────────────────────
function Donut({ pct, color, size = 56 }) {
  const r = size * 0.38, cx = size / 2, cy = size / 2;
  const circ = 2 * Math.PI * r;
  const dash  = (pct / 100) * circ;
  return (
    <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
      <circle cx={cx} cy={cy} r={r} fill="none" stroke="#1e293b" strokeWidth={size * 0.13} />
      <circle cx={cx} cy={cy} r={r} fill="none"
        stroke={color} strokeWidth={size * 0.13}
        strokeDasharray={`${dash} ${circ}`} strokeLinecap="round"
        transform={`rotate(-90 ${cx} ${cy})`}
        style={{ transition: "stroke-dasharray 1s ease" }} />
      <text x="50%" y="50%" dominantBaseline="middle" textAnchor="middle"
        fill="white" fontSize={size * 0.22} fontWeight="700">{pct}%</text>
    </svg>
  );
}

// ── Navbar ─────────────────────────────────────────────────────────────────
function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  return (
    <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 ${scrolled ? "bg-slate-950/90 backdrop-blur-xl border-b border-slate-800/60" : "bg-transparent"}`}>
      <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
        {/* Logo */}
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-xl bg-gradient-to-br from-amber-400 to-orange-500 flex items-center justify-center text-base">🇱🇰</div>
          <span className="text-white font-bold tracking-tight" style={{ fontFamily: "'Sora', sans-serif" }}>
            Promise<span className="text-amber-400">Watch</span>
          </span>
        </div>
        {/* Links */}
        <div className="hidden md:flex items-center gap-8">
          {["Politicians", "Promises", "News", "About"].map(l => (
            <a key={l} href="#" className="text-slate-400 hover:text-white text-sm transition-colors">{l}</a>
          ))}
        </div>
        {/* CTA */}
        <div className="flex items-center gap-3">
          <button className="text-slate-400 hover:text-white text-sm transition-colors">Sign in</button>
          <button className="px-4 py-2 text-sm font-semibold rounded-xl bg-gradient-to-r from-amber-400 to-orange-500 text-black hover:opacity-90 transition">
            Get Alerts
          </button>
        </div>
      </div>
    </nav>
  );
}

// ── Hero ───────────────────────────────────────────────────────────────────
function Hero() {
  const [filterActive, setFilterActive] = useState("All");
  const filters = ["All", "Kept", "In Progress", "Broken", "Pending"];

  return (
    <section className="relative min-h-screen flex flex-col items-center justify-center overflow-hidden pt-16">
      {/* Background effects */}
      <div className="absolute inset-0 bg-slate-950" />
      <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[900px] h-[500px] rounded-full bg-amber-500/5 blur-[120px] pointer-events-none" />
      <div className="absolute bottom-0 left-0 w-[400px] h-[400px] rounded-full bg-rose-500/5 blur-[100px] pointer-events-none" />
      <div className="absolute top-1/3 right-0 w-[300px] h-[300px] rounded-full bg-emerald-500/5 blur-[100px] pointer-events-none" />

      {/* Grid overlay */}
      <div className="absolute inset-0 opacity-[0.03]"
        style={{ backgroundImage: "linear-gradient(rgba(255,255,255,.3) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,.3) 1px,transparent 1px)", backgroundSize: "60px 60px" }} />

      {/* Content */}
      <div className="relative z-10 max-w-5xl mx-auto px-6 text-center">
        <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-amber-500/10 border border-amber-500/20 text-amber-400 text-xs font-medium mb-8">
          <span className="w-1.5 h-1.5 rounded-full bg-amber-400 animate-pulse" />
          Live · Tracking 89 Politicians · Sri Lanka
        </div>

        <h1 className="text-5xl md:text-7xl font-black text-white leading-[1.05] tracking-tight mb-6"
          style={{ fontFamily: "'Sora', sans-serif" }}>
          Did They Keep
          <br />
          <span className="relative inline-block">
            <span className="relative z-10 bg-gradient-to-r from-amber-400 via-orange-400 to-rose-400 bg-clip-text text-transparent">
              Their Promises?
            </span>
            <span className="absolute -bottom-1 left-0 right-0 h-1 bg-gradient-to-r from-amber-400/40 to-rose-400/40 blur-sm rounded-full" />
          </span>
        </h1>

        <p className="text-slate-400 text-lg md:text-xl max-w-2xl mx-auto leading-relaxed mb-10">
          Sri Lanka's first open platform for tracking political promises — from election day to delivery. No spin. Just facts.
        </p>

        <div className="flex flex-col sm:flex-row items-center justify-center gap-4 mb-14">
          <button className="group px-8 py-3.5 rounded-2xl bg-gradient-to-r from-amber-400 to-orange-500 text-black font-bold text-sm hover:opacity-90 transition flex items-center gap-2 shadow-lg shadow-amber-500/20">
            Explore All Promises
            <span className="group-hover:translate-x-1 transition-transform">→</span>
          </button>
          <button className="px-8 py-3.5 rounded-2xl bg-slate-800/60 border border-slate-700/60 text-white text-sm font-medium hover:bg-slate-800 transition">
            🔔 Subscribe to Alerts
          </button>
        </div>

        {/* Filter tabs */}
        <div className="flex items-center justify-center gap-2 flex-wrap mb-8">
          {filters.map(f => (
            <button key={f} onClick={() => setFilterActive(f)}
              className={`px-4 py-2 rounded-full text-xs font-medium transition-all border ${
                filterActive === f
                  ? "bg-white/10 text-white border-white/20"
                  : "text-slate-500 border-slate-800 hover:text-slate-300 hover:border-slate-600"
              }`}>
              {f}
            </button>
          ))}
        </div>

        {/* Promise cards strip */}
        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-3 max-w-4xl mx-auto">
          {PROMISES
            .filter(p => filterActive === "All" || p.status === filterActive)
            .slice(0, 6)
            .map((p, i) => {
              const cfg = STATUS_CFG[p.status];
              return (
                <div key={i}
                  className={`${cfg.bg} border ${cfg.border} rounded-2xl p-4 text-left hover:scale-[1.02] transition-transform cursor-pointer`}
                  style={{ animationDelay: `${i * 0.05}s` }}>
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-base">{CAT_ICONS[p.category] || "📌"}</span>
                    <span className={`inline-flex items-center gap-1 text-xs font-medium ${cfg.text}`}>
                      <span className={`w-1.5 h-1.5 rounded-full ${cfg.dot}`} />
                      {p.status}
                    </span>
                  </div>
                  <p className="text-slate-200 text-sm font-medium leading-snug mb-2">{p.text}</p>
                  <div className="flex items-center justify-between">
                    <span className="text-slate-500 text-xs font-mono">{p.politician}</span>
                    <span className="text-slate-600 text-xs">{p.days}d ago</span>
                  </div>
                </div>
              );
            })}
        </div>
      </div>

      {/* Scroll cue */}
      <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex flex-col items-center gap-2 text-slate-600">
        <span className="text-xs">Scroll to explore</span>
        <div className="w-px h-8 bg-gradient-to-b from-slate-600 to-transparent" />
      </div>
    </section>
  );
}

// ── Stats ──────────────────────────────────────────────────────────────────
function StatsSection() {
  return (
    <section className="py-20 border-y border-slate-800/60 bg-slate-900/30">
      <div className="max-w-6xl mx-auto px-6">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
          {STATS.map((s, i) => (
            <div key={i} className="text-center group">
              <div className="text-3xl mb-3">{s.icon}</div>
              <div className="text-4xl font-black text-white mb-1" style={{ fontFamily: "'Sora', sans-serif" }}>
                <Counter target={s.value} />{s.suffix}
              </div>
              <div className="text-slate-500 text-sm">{s.label}</div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

// ── Politicians ────────────────────────────────────────────────────────────
function PoliticiansSection() {
  return (
    <section className="py-24">
      <div className="max-w-6xl mx-auto px-6">
        <div className="flex items-end justify-between mb-12">
          <div>
            <p className="text-amber-400 text-xs font-semibold uppercase tracking-widest mb-3">Accountability Index</p>
            <h2 className="text-3xl md:text-4xl font-black text-white" style={{ fontFamily: "'Sora', sans-serif" }}>
              Top Politicians
            </h2>
          </div>
          <a href="#" className="text-slate-400 hover:text-white text-sm transition-colors">View all →</a>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {POLITICIANS.map((p, i) => {
            const pct = Math.round((p.kept / p.total) * 100);
            return (
              <div key={i}
                className="bg-slate-900/60 border border-slate-800/60 rounded-3xl p-6 hover:border-slate-700/80 transition-all group cursor-pointer hover:-translate-y-1">
                {/* Header */}
                <div className="flex items-center gap-4 mb-6">
                  <div className="w-14 h-14 rounded-2xl flex items-center justify-center text-lg font-black text-black shrink-0"
                    style={{ background: p.color }}>{p.avatar}</div>
                  <div className="flex-1 min-w-0">
                    <div className="text-white font-bold text-sm truncate">{p.name}</div>
                    <div className="text-slate-400 text-xs mt-0.5">{p.role}</div>
                    <div className="inline-flex items-center mt-1 px-2 py-0.5 rounded-full text-xs font-medium bg-slate-800 text-slate-300 border border-slate-700/50">
                      {p.party}
                    </div>
                  </div>
                  <Donut pct={pct} color={p.color} size={52} />
                </div>

                {/* Progress bar */}
                <div className="mb-4">
                  <div className="flex justify-between text-xs text-slate-500 mb-1.5">
                    <span>Promise fulfilment</span>
                    <span>{p.kept} / {p.total}</span>
                  </div>
                  <div className="h-2 bg-slate-800 rounded-full overflow-hidden">
                    <div className="h-full rounded-full transition-all duration-1000"
                      style={{ width: `${pct}%`, background: p.color }} />
                  </div>
                </div>

                {/* Tags */}
                <div className="flex gap-2 flex-wrap">
                  {p.tags.map(t => (
                    <span key={t} className="px-2.5 py-1 rounded-lg bg-slate-800/80 text-slate-400 text-xs border border-slate-700/40">
                      {CAT_ICONS[t]} {t}
                    </span>
                  ))}
                </div>

                <div className="mt-4 pt-4 border-t border-slate-800/60 flex items-center justify-between">
                  <span className="text-slate-500 text-xs">View promises</span>
                  <span className="text-slate-500 group-hover:text-white text-xs transition-colors">→</span>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </section>
  );
}

// ── How It Works ───────────────────────────────────────────────────────────
function HowItWorks() {
  const steps = [
    { num: "01", icon: "🗳️", title: "Politicians Make Promises", desc: "We log every public promise made during campaigns, speeches, and in parliament with source links and dates." },
    { num: "02", icon: "🔍", title: "We Track Progress", desc: "Our team monitors news, official statements, and government records to update the status of each pledge." },
    { num: "03", icon: "👥", title: "Citizens Verify", desc: "Anyone can submit evidence, upvote/downvote truthfulness ratings, and add comments to hold leaders accountable." },
    { num: "04", icon: "🔔", title: "You Stay Informed", desc: "Subscribe to your district politicians and get notified when a promise status changes or new evidence appears." },
  ];

  return (
    <section className="py-24 bg-slate-900/30 border-y border-slate-800/60">
      <div className="max-w-6xl mx-auto px-6">
        <div className="text-center mb-16">
          <p className="text-amber-400 text-xs font-semibold uppercase tracking-widest mb-3">How It Works</p>
          <h2 className="text-3xl md:text-4xl font-black text-white" style={{ fontFamily: "'Sora', sans-serif" }}>
            Accountability, Step by Step
          </h2>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
          {steps.map((s, i) => (
            <div key={i} className="relative">
              {i < steps.length - 1 && (
                <div className="hidden md:block absolute top-8 left-[calc(100%-12px)] w-6 h-px bg-slate-700 z-10" />
              )}
              <div className="bg-slate-900/80 border border-slate-800/60 rounded-3xl p-6 h-full hover:border-slate-700/80 transition-all">
                <div className="text-amber-400/40 text-xs font-mono font-bold mb-4">{s.num}</div>
                <div className="text-3xl mb-4">{s.icon}</div>
                <h3 className="text-white font-bold text-sm mb-2">{s.title}</h3>
                <p className="text-slate-500 text-xs leading-relaxed">{s.desc}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

// ── News Feed ──────────────────────────────────────────────────────────────
function NewsSection() {
  return (
    <section className="py-24">
      <div className="max-w-6xl mx-auto px-6">
        <div className="flex items-end justify-between mb-12">
          <div>
            <p className="text-amber-400 text-xs font-semibold uppercase tracking-widest mb-3">Live Intelligence</p>
            <h2 className="text-3xl md:text-4xl font-black text-white" style={{ fontFamily: "'Sora', sans-serif" }}>
              Latest News
            </h2>
          </div>
          <a href="#" className="text-slate-400 hover:text-white text-sm transition-colors">All news →</a>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {NEWS.map((n, i) => (
            <div key={i}
              className="bg-slate-900/60 border border-slate-800/60 rounded-2xl p-5 flex items-start gap-4 hover:border-slate-700/80 transition-all cursor-pointer group">
              <div className="w-10 h-10 rounded-xl bg-slate-800 flex items-center justify-center text-lg shrink-0">
                {CAT_ICONS[n.tag] || "📰"}
              </div>
              <div className="flex-1 min-w-0">
                <div className="inline-flex items-center px-2 py-0.5 rounded-full bg-amber-500/10 border border-amber-500/20 text-amber-400 text-xs font-medium mb-2">
                  {n.tag}
                </div>
                <p className="text-slate-200 text-sm font-medium leading-snug group-hover:text-white transition-colors">{n.headline}</p>
                <p className="text-slate-600 text-xs mt-1">{n.time}</p>
              </div>
              <span className="text-slate-600 group-hover:text-white text-sm transition-colors shrink-0">→</span>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

// ── CTA ────────────────────────────────────────────────────────────────────
function CTASection() {
  const [email, setEmail] = useState("");
  const [sent, setSent] = useState(false);

  return (
    <section className="py-24 relative overflow-hidden">
      <div className="absolute inset-0 bg-gradient-to-br from-amber-500/5 via-transparent to-rose-500/5" />
      <div className="absolute top-0 left-1/2 -translate-x-1/2 w-[600px] h-[300px] bg-amber-400/5 blur-[100px] rounded-full" />
      <div className="relative z-10 max-w-3xl mx-auto px-6 text-center">
        <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-slate-800/80 border border-slate-700/60 text-slate-400 text-xs mb-8">
          🔔 Get real-time promise updates
        </div>
        <h2 className="text-4xl md:text-5xl font-black text-white mb-6" style={{ fontFamily: "'Sora', sans-serif" }}>
          Never Miss a
          <span className="bg-gradient-to-r from-amber-400 to-orange-400 bg-clip-text text-transparent"> Broken Promise</span>
        </h2>
        <p className="text-slate-400 text-lg mb-10 leading-relaxed">
          Subscribe to get alerts when your district politicians update their promise status. No fluff — just accountability.
        </p>

        {sent ? (
          <div className="inline-flex items-center gap-3 px-6 py-4 rounded-2xl bg-emerald-500/10 border border-emerald-500/20 text-emerald-400">
            ✅ You're on the list! We'll notify you as promises are updated.
          </div>
        ) : (
          <div className="flex flex-col sm:flex-row gap-3 max-w-md mx-auto">
            <input
              type="email"
              value={email}
              onChange={e => setEmail(e.target.value)}
              placeholder="your@email.com"
              className="flex-1 bg-slate-800/60 border border-slate-700/60 rounded-2xl px-5 py-3.5 text-sm text-white placeholder-slate-500 focus:outline-none focus:border-amber-500/50 transition"
            />
            <button
              onClick={() => email && setSent(true)}
              className="px-6 py-3.5 rounded-2xl bg-gradient-to-r from-amber-400 to-orange-500 text-black font-bold text-sm hover:opacity-90 transition shadow-lg shadow-amber-500/20 whitespace-nowrap">
              Get Alerts →
            </button>
          </div>
        )}

        <p className="text-slate-600 text-xs mt-4">No spam · Unsubscribe anytime · Built for Sri Lankan citizens</p>
      </div>
    </section>
  );
}

// ── Footer ─────────────────────────────────────────────────────────────────
function Footer() {
  return (
    <footer className="border-t border-slate-800/60 bg-slate-900/30 py-12">
      <div className="max-w-6xl mx-auto px-6">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-8 mb-12">
          <div className="col-span-2 md:col-span-1">
            <div className="flex items-center gap-2 mb-4">
              <div className="w-7 h-7 rounded-lg bg-gradient-to-br from-amber-400 to-orange-500 flex items-center justify-center text-sm">🇱🇰</div>
              <span className="text-white font-bold" style={{ fontFamily: "'Sora', sans-serif" }}>
                Promise<span className="text-amber-400">Watch</span>
              </span>
            </div>
            <p className="text-slate-500 text-xs leading-relaxed">
              Tracking political accountability across Sri Lanka since 2024.
            </p>
          </div>
          {[
            { heading: "Platform", links: ["Politicians", "Promises", "Districts", "Statistics"] },
            { heading: "Community", links: ["Submit Evidence", "Citizen Forum", "Fact Checkers", "API Access"] },
            { heading: "Company", links: ["About", "Methodology", "Contact", "Privacy"] },
          ].map(col => (
            <div key={col.heading}>
              <h4 className="text-slate-300 text-xs font-semibold uppercase tracking-wider mb-4">{col.heading}</h4>
              <ul className="space-y-2">
                {col.links.map(l => (
                  <li key={l}>
                    <a href="#" className="text-slate-500 hover:text-slate-300 text-xs transition-colors">{l}</a>
                  </li>
                ))}
              </ul>
            </div>
          ))}
        </div>

        <div className="border-t border-slate-800/60 pt-6 flex flex-col md:flex-row items-center justify-between gap-4">
          <p className="text-slate-600 text-xs">© 2026 PromiseWatch Sri Lanka. Built for citizens, by citizens.</p>
          <div className="flex items-center gap-4">
            {["Twitter", "Facebook", "GitHub"].map(s => (
              <a key={s} href="#" className="text-slate-600 hover:text-slate-300 text-xs transition-colors">{s}</a>
            ))}
          </div>
        </div>
      </div>
    </footer>
  );
}

// ── Root ───────────────────────────────────────────────────────────────────
export default function HomePage() {
  return (
    <>
      {/* Google Font */}
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Sora:wght@400;600;700;800;900&display=swap');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        body { background: #020617; }
        html { scroll-behavior: smooth; }
      `}</style>

      <div className="bg-slate-950 min-h-screen">
        <Navbar />
        <Hero />
        <StatsSection />
        <PoliticiansSection />
        <HowItWorks />
        <NewsSection />
        <CTASection />
        <Footer />
      </div>
    </>
  );
}
